1: window.Commands = (function () {
2: 
3:   // ── Virtual Filesystem ─────────────────────────────────
4: 
5:   const FS = {
6:     '~': ['about', 'skills', 'projects', 'contact', 'README.md'],
7:     '~/about':    ['bio.txt', 'experience.txt'],
8:     '~/skills':   ['languages.txt', 'frameworks.txt', 'devops.txt'],
9:     '~/projects': [],      // populated from PF.projects on init
10:     '~/contact':  ['links.txt'],
11:   };
12: 
13:   let cwd = '~';
14: 
15:   // Runs after PF (portfolio data) is loaded
16:   function init () {
17:     if (window.PF && PF.projects) {
18:       FS['~/projects'] = PF.projects.map(p => p.slug + '.md');
19:     }
20:   }
21: 
22:   // ── Path Resolution ───────────────────────────────────
23: 
24:   function resolvePath (target) {
25:     if (target === '..')  return cwd.includes('/') ? cwd.split('/').slice(0,-1).join('/') : '~';
26:     if (target === '~')   return '~';
27:     if (target.startsWith('~/')) return target;
28:     return cwd === '~' ? `~/${target}` : `${cwd}/${target}`;
29:   }
30: 
31:   // ── Handlers (each returns a string or array of strings) ──
32: 
33:   function cmdHelp () {
34:     return [
35:       '',
36:       '[[b;#ff8c00;]Available Commands]',
37:       '',
38:       '  [[;#ffb000;]help]         Show this message',
39:       '  [[;#ffb000;]ls]           List directory contents',
40:       '  [[;#ffb000;]cd <dir>]     Change directory',
41:       '  [[;#ffb000;]cat <file>]   Print file contents',
42:       '  [[;#ffb000;]about]        Quick bio',
43:       '  [[;#ffb000;]skills]       Technical skills overview',
44:       '  [[;#ffb000;]projects]     Project showcase',
45:       '  [[;#ffb000;]contact]      How to reach me',
46:       '  [[;#ffb000;]ezra]         Chat with my AI assistant',
47:       '  [[;#ffb000;]clear]        Clear the screen',
48:       '  [[;#ffb000;]reset]        Reload portfolio',
49:       '',
50:       '  [[;#555;]Hint: try exploring with ls and cd...]',
51:       '',
52:     ];
53:   }
54: 
55:   function cmdLs (args) {
56:     const target = args[0] ? resolvePath(args[0]) : cwd;
57:     const contents = FS[target];
58:     if (!contents) return `ls: cannot access '${args[0]}': No such file or directory`;
59:     if (contents.length === 0) return '(empty)';
60: 
61:     return contents.map(item => {
62:       const isDir = !!FS[`${target}/${item}`] || FS[`~/${item}`] !== undefined;
63:       return isDir
64:         ? `[[b;#ffd060;]${item}/]`
65:         : `[[;#ffb000;]${item}]`;
66:     }).join('  ');
67:   }
68: 
69:   function cmdCd (args) {
70:     if (!args[0] || args[0] === '~') { cwd = '~'; return `[[;#888;]Changed to ~]`; }
71:     const target = resolvePath(args[0]);
72:     if (FS[target] !== undefined) {
73:       cwd = target;
74:       return `[[;#888;]Changed to ${cwd}]`;
75:     }
76:     return `cd: ${args[0]}: No such directory`;
77:   }
78: 
79:   function cmdCat (args) {
80:     if (!args[0]) return 'Usage: cat <file>';
81:     const fullPath = `${cwd}/${args[0]}`;
82: 
83:     // ── Static file mapping ──────────────────────────
84: 
85:     if (args[0] === 'README.md') {
86:       return [
87:         '',
88:         `[[b;#ff8c00;]${PF.owner.name}'s Portfolio CLI]`,
89:         `[[;#ffb000;]${PF.owner.tagline}]`,
90:         '',
91:         `Type [[b;#ffd060;]help] for available commands.`,
92:         '',
93:       ];
94:     }
95: 
96:     if (fullPath.includes('bio.txt') || args[0] === 'bio.txt') {
97:       return PF.about.map(l => `  ${l}`);
98:     }
99: 
100:     if (args[0] === 'languages.txt') {
101:       return PF.skills.Languages.map(s => `  [[;#ffb000;]•] ${s}`);
102:     }
103:     if (args[0] === 'frameworks.txt') {
104:       return PF.skills.Frontend.concat(PF.skills.Backend).map(s => `  [[;#ffb000;]•] ${s}`);
105:     }
106:     if (args[0] === 'devops.txt') {
107:       return PF.skills.DevOps.map(s => `  [[;#ffb000;]•] ${s}`);
108:     }
109: 
110:     if (args[0] === 'links.txt') {
111:       const c = PF.contact;
112:       return [
113:         `  Email:    ${c.email}`,
114:         `  GitHub:   ${c.github}`,
115:         `  LinkedIn: ${c.linkedin}`,
116:         `  Twitter:  ${c.twitter}`,
117:       ];
118:     }
119: 
120:     // ── Dynamic project files ────────────────────────
121: 
122:     if (cwd === '~/projects' || args[0].endsWith('.md')) {
123:       const slug = args[0].replace('.md', '');
124:       const proj = PF.projects.find(p => p.slug === slug);
125:       if (proj) {
126:         return [
127:           '',
128:           `[[b;#ff8c00;]${proj.name}]  (${proj.year})`,
129:           `${proj.desc}`,
130:           '',
131:           `Tech: [[;#ffd060;]${proj.tech.join(', ')}]`,
132:           `URL:  ${proj.url}`,
133:           '',
134:         ];
135:       }
136:     }
137: 
138:     return `cat: ${args[0]}: No such file`;
139:   }
140: 
141:   function cmdAbout () {
142:     return [
143:       '',
144:       `[[b;#ff8c00;]${PF.owner.name}]  —  ${PF.owner.title}`,
145:       `[[;#888;]${PF.owner.location}]`,
146:       '',
147:       ...PF.about.map(l => `  ${l}`),
148:       '',
149:     ];
150:   }
151: 
152:   function cmdSkills () {
153:     const lines = [''];
154:     for (const [cat, items] of Object.entries(PF.skills)) {
155:       lines.push(`[[b;#ff8c00;]${cat}]`);
156:       lines.push(`  ${items.join('  ')}`);
157:       lines.push('');
158:     }
159:     return lines;
160:   }
161: 
162:   function cmdProjects () {
163:     const lines = [''];
164:     for (const p of PF.projects) {
165:       lines.push(`[[b;#ffd060;]${p.name}]  (${p.year})`);
166:       lines.push(`  ${p.desc}`);
167:       lines.push(`  [[;#888;]${p.tech.join(', ')}]`);
168:       lines.push(`  ${p.url}`);
169:       lines.push('');
170:     }
171:     lines.push(`Type [[b;#ffb000;]cd projects && ls] to explore project files.`);
172:     lines.push('');
173:     return lines;
174:   }
175: 
176:   function cmdContact () {
177:     const c = PF.contact;
178:     return [
179:       '',
180:       `  [[;#ffb000;]Email]    ${c.email}`,
181:       `  [[;#ffb000;]GitHub]   ${c.github}`,
182:       `  [[;#ffb000;]LinkedIn] ${c.linkedin}`,
183:       `  [[;#ffb000;]Twitter]  ${c.twitter}`,
184:       '',
185:     ];
186:   }
187: 
188:   // ── Public Interpreter (passed to jQuery Terminal) ──────
189: 
190:   function interpreter (cmd, term) {
191:     // Ignore empty input
192:     if (!cmd.trim()) return;
193: 
194:     const parts = cmd.trim().split(/\s+/);
195:     const name  = parts[0].toLowerCase();
196:     const args  = parts.slice(1);
197: 
198:     switch (name) {
199:       case 'help':     term.echo(cmdHelp().join('\n'));    break;
200:       case 'ls':       term.echo(cmdLs(args));             break;
201:       case 'cd':       term.echo(cmdCd(args));             break;
202:       case 'cat':      term.echo(cmdCat(args).join ? cmdCat(args).join('\n') : cmdCat(args)); break;
203:       case 'about':    term.echo(cmdAbout().join('\n'));   break;
204:       case 'skills':   term.echo(cmdSkills().join('\n'));  break;
205:       case 'projects': term.echo(cmdProjects().join('\n'));break;
206:       case 'contact':  term.echo(cmdContact().join('\n')); break;
207:       case 'clear':    term.clear();                       break;
208:       case 'reset':    window.location.reload();           break;
209:       case 'ezra':     window.Chatbot.start(term);         break;
210:       case 'snake':    window.Snake.launch(term);          break;
211: 
212:       // Unknown command
213:       default:
214:         term.error(`${name}: command not found. Type [[b;#ffd060;]help] for usage.`);
215:     }
216:   }
217: 
218:   return { init, interpreter };
219: 
220: })();   // end Commands IIFE
221: 
