1: // ── Snake mini-game (Canvas-based) ──
2: 
3: window.Snake = (function () {
4: 
5:   const TILE  = 16;
6:   const W     = 26;   // tiles wide
7:   const H     = 20;   // tiles tall
8:   const DELAY = 110;  // ms per tick
9: 
10:   let canvas, ctx, term, raf, running, dir, nextDir, body, food, score;
11: 
12:   function launch (_term) {
13:     term    = _term;
14:     running = false;
15: 
16:     // Create canvas overlay
17:     canvas        = document.createElement('canvas');
18:     canvas.width  = W * TILE;
19:     canvas.height = H * TILE;
20:     canvas.style.cssText = `
21:       position:absolute; top:50%; left:50%;
22:       transform:translate(-50%,-50%);
23:       z-index:50; border:2px solid #ffb000;
24:       background:#000; image-rendering:pixelated;
25:     `;
26:     canvas.setAttribute('aria-label', 'Snake game');
27: 
28:     ctx = canvas.getContext('2d');
29:     document.getElementById('crt-wrap').appendChild(canvas);
30: 
31:     // Keyboard
32:     document.addEventListener('keydown', onKey);
33: 
34:     // Touch (mobile)
35:     canvas.addEventListener('touchstart', onTouch, { passive: true });
36: 
37:     resetGame();
38:     term.echo('[[b;#ff8c00;]SNAKE] — Arrow keys to move. Q to quit.');
39:     running = true;
40:     raf = setTimeout(tick, DELAY);
41:   }
42: 
43:   function resetGame () {
44:     dir     = { x: 1, y: 0 };
45:     nextDir = { x: 1, y: 0 };
46:     body    = [{ x: 13, y: 10 }, { x: 12, y: 10 }, { x: 11, y: 10 }];
47:     score   = 0;
48:     spawnFood();
49:     draw();
50:   }
51: 
52:   function spawnFood () {
53:     do {
54:       food = { x: Math.floor(Math.random() * W),
55:                y: Math.floor(Math.random() * H) };
56:     } while (body.some(s => s.x === food.x && s.y === food.y));
57:   }
58: 
59:   function tick () {
60:     if (!running) return;
61:     dir = nextDir;
62:     const head = { x: (body[0].x + dir.x + W) % W,
63:                    y: (body[0].y + dir.y + H) % H };
64: 
65:     // Collision with self
66:     if (body.some(s => s.x === head.x && s.y === head.y)) {
67:       gameOver(); return;
68:     }
69: 
70:     body.unshift(head);
71: 
72:     if (head.x === food.x && head.y === food.y) {
73:       score++;
74:       spawnFood();
75:     } else {
76:       body.pop();
77:     }
78: 
79:     draw();
80:     raf = setTimeout(tick, DELAY);
81:   }
82: 
83:   function draw () {
84:     ctx.fillStyle = '#000';
85:     ctx.fillRect(0, 0, canvas.width, canvas.height);
86: 
87:     // Grid dots
88:     ctx.fillStyle = '#1a0a00';
89:     for (let x = 0; x < W; x++)
90:       for (let y = 0; y < H; y++)
91:         ctx.fillRect(x * TILE + 7, y * TILE + 7, 2, 2);
92: 
93:     // Food
94:     ctx.fillStyle = '#ff5500';
95:     ctx.shadowColor = '#ff5500';
96:     ctx.shadowBlur = 8;
97:     ctx.fillRect(food.x * TILE + 2, food.y * TILE + 2, TILE - 4, TILE - 4);
98:     ctx.shadowBlur = 0;
99: 
100:     // Snake
101:     body.forEach((seg, i) => {
102:       const t = 1 - (i / body.length) * 0.5;
103:       ctx.fillStyle = `rgba(255,${Math.floor(176*t)},0,1)`;
104:       ctx.fillRect(seg.x * TILE + 1, seg.y * TILE + 1, TILE - 2, TILE - 2);
105:     });
106: 
107:     // Score
108:     ctx.fillStyle = '#ffb000';
109:     ctx.font = '11px monospace';
110:     ctx.fillText(`SCORE: ${score}`, 6, 14);
111:   }
112: 
113:   function gameOver () {
114:     running = false;
115:     ctx.fillStyle = 'rgba(0,0,0,0.7)';
116:     ctx.fillRect(0, 0, canvas.width, canvas.height);
117:     ctx.fillStyle = '#ff5500';
118:     ctx.font = 'bold 20px monospace';
119:     ctx.textAlign = 'center';
120:     ctx.fillText('GAME OVER', canvas.width/2, canvas.height/2 - 10);
121:     ctx.fillStyle = '#ffb000';
122:     ctx.font = '13px monospace';
123:     ctx.fillText(`Score: ${score}`, canvas.width/2, canvas.height/2 + 14);
124:     ctx.fillText('Press Q to exit', canvas.width/2, canvas.height/2 + 34);
125:     ctx.textAlign = 'left';
126:   }
127: 
128:   function quit () {
129:     running = false;
130:     clearTimeout(raf);
131:     document.removeEventListener('keydown', onKey);
132:     if (canvas && canvas.parentNode) canvas.parentNode.removeChild(canvas);
133:   }
134: 
135:   function onKey (e) {
136:     const map = {
137:       ArrowUp:    { x: 0, y: -1 }, ArrowDown:  { x: 0, y:  1 },
138:       ArrowLeft:  { x:-1, y:  0 }, ArrowRight: { x: 1, y:  0 },
139:     };
140:     if (map[e.key] && !(dir.x === -map[e.key].x && dir.y === -map[e.key].y)) {
141:       nextDir = map[e.key];
142:       e.preventDefault();
143:     }
144:     if (e.key === 'q' || e.key === 'Q') {
145:       quit();
146:       term.echo('[[;#888;]Snake closed.]');
147:     }
148:   }
149: 
150:   let touchStart = null;
151:   function onTouch (e) {
152:     touchStart = { x: e.touches[0].clientX, y: e.touches[0].clientY };
153:     canvas.addEventListener('touchend', onTouchEnd, { once: true });
154:   }
155:   function onTouchEnd (e) {
156:     if (!touchStart) return;
157:     const dx = e.changedTouches[0].clientX - touchStart.x;
158:     const dy = e.changedTouches[0].clientY - touchStart.y;
159:     if (Math.abs(dx) > Math.abs(dy)) {
160:       nextDir = dx > 0 ? { x:1,y:0 } : { x:-1,y:0 };
161:     } else {
162:       nextDir = dy > 0 ? { x:0,y:1 } : { x:0,y:-1 };
163:     }
164:     touchStart = null;
165:   }
166: 
167:   return { launch };
168: 
169: })();
